const data = $input.first().json;
const raw = data?.text || data?.output || data?.content?.[0]?.text || '';
if (!raw) throw new Error('Empty response from SEO brief LLM call');

const cleaned = raw.replace(/```json\n?/gi,'').replace(/```\n?/g,'').trim();

// Extract outermost JSON object using balanced-brace tracking.
// Greedy regex /{[\s\S]*}/ fails when Gemini appends trailing text after the JSON.
function extractJson(str) {
  const start = str.indexOf('{');
  if (start === -1) return null;
  let depth = 0;
  for (let i = start; i < str.length; i++) {
    if (str[i] === '{') depth++;
    else if (str[i] === '}') {
      depth--;
      if (depth === 0) return str.slice(start, i + 1);
    }
  }
  return null;
}

let brief;
try {
  brief = JSON.parse(cleaned);
} catch(e) {
  const extracted = extractJson(cleaned);
  if (extracted) {
    try { brief = JSON.parse(extracted); }
    catch(e2) { throw new Error('Brief JSON parse failed after extraction: ' + extracted.slice(0,300)); }
  } else {
    throw new Error('Brief JSON parse failed — no JSON object found. Raw: ' + cleaned.slice(0,300));
  }
}

return [{ json: brief }];

const topic = $('⑥ Code: Parse Topic JSON').first().json;
const brief = $input.first().json;
const vars = $('③ Code: Set Pipeline Variables').first().json;

const sectionText = (brief.sections || []).map((s, i) => {
  let t = `Section ${i+1}: ${s.h2}\n  What to cover: ${s.notes}`;
  if (s.h3s && s.h3s.length) t += `\n  Subheadings: ${s.h3s.join(' | ')}`;
  if (s.internalLink) t += `\n  Embed link: [${s.internalLink.anchor}](${vars.siteUrl}${s.internalLink.url})`;
  return t;
}).join('\n\n');

const lsiText = (brief.keywordPlacement?.lsiPlacements || []).map(p => `  - "${p.keyword}" → in ${p.section}`).join('\n');
const sourcesText = (brief.externalSources || []).map(s => `  - ${s.name} (${s.type}): ${s.relevance}`).join('\n');
const statsText = (brief.statsToInclude || []).map(s => `  - ${s}`).join('\n');
const allInternalLinks = (brief.sections || []).filter(s => s.internalLink).map(s => `[${s.internalLink.anchor}](${vars.siteUrl}${s.internalLink.url})`);

const prompt = `You are Belle Bai, Marketing Executive at TesseractApps — an Australian care management software company. You have 8 years working with NDIS providers, aged care operators, and disability support organisations across Australia. You write with authority, empathy, and a genuine point of view.

## YOUR WRITING BRIEF

Title: ${topic.title}
H1: ${brief.h1 || topic.title}
Primary keyword: ${topic.primaryKeyword}
LSI keywords: ${(topic.lsiKeywords || []).join(', ')}
Search intent: ${topic.searchIntent}
Content type: ${topic.contentType}
Target audience: ${topic.targetAudience}
Editorial stance: ${brief.editorialStance}
Intro hook: ${brief.intro}
Target word count: ${topic.estimatedWordCount} words
Category: ${vars.category}

## SECTION STRUCTURE
${sectionText}

## KEYWORD PLACEMENT
Primary keyword: ${(brief.keywordPlacement?.primaryKeyword || []).join(', ')}
LSI placements:
${lsiText}

## EXTERNAL SOURCES TO REFERENCE
${sourcesText}

## STATS TO WEAVE IN
${statsText}

## CTA GUIDANCE
${brief.ctaSection}

## INTERNAL LINKS TO EMBED
${allInternalLinks.join('\n')}
(embed only where they flow naturally — max 5)

---

## NON-NEGOTIABLE WRITING RULES

1. HUMAN VOICE — Write as Belle Bai. Use "we", "I've seen", "in our experience". Share genuine opinions.
2. ORIGINAL THOUGHT — Have a real point of view. If the sector is doing something wrong, say so.
3. AUSTRALIAN ENGLISH — organise, labour, practise, behaviour, recognise, centre, colour. Always.
4. SEO DONE RIGHT — Primary keyword in first 100 words, in at least one H2, and in conclusion. Spread LSI keywords naturally. Never keyword-stuff.
5. INTERNAL LINKS — Embed as markdown [anchor](https://tesseractapps.com/page). Only where it genuinely helps. Max 5.
6. EXTERNAL CREDIBILITY — Reference NDIS Commission, Aged Care Quality and Safety Commission, NDIS Pricing Arrangements, Fair Work Act, or other real Australian sources. By name only — no invented URLs.
7. STRUCTURE — Follow H2/H3 structure exactly. 2-4 solid paragraphs per section. No filler.
8. TONE — Expert but human. Serious when needed, conversational when appropriate. Zero corporate jargon.
9. SOFT CTA — ONE brief mention of TesseractApps in the specified section only. Never a hard sales pitch.
10. START DIRECTLY — Begin with the intro paragraph. No title heading. No "Introduction:". Hook the reader immediately.
11. END WELL — Conclusion reinforces editorial stance, uses primary keyword, leaves reader with an insight.

---

Write the complete blog post in markdown now. Do NOT include the H1 title. Do NOT include frontmatter or JSON. Aim for ${topic.estimatedWordCount} words.`;

return [{ json: { prompt, topic, brief, vars } }];

const data = $input.first().json;
// chainLlm returns { text: '...' } — this is the correct shape to check
